def solve(nums: Array[Long], k: Long): Long = {
    val sorted = nums.sorted
    var minRemovals = Long.MaxValue
    val n = sorted.length

    for (i <- 0 until n) {
        val minVal = sorted(i)
        val maxValUpper = minVal * k
        var left = i
        var right = n - 1
        var bestJ = i

        while (left <= right) {
            val mid = left + (right - left) / 2
            if (sorted(mid) <= maxValUpper) {
                bestJ = mid
                left = mid + 1
            } else {
                right = mid - 1
            }
        }

        val removals = (n - (bestJ - i + 1)).toLong
        if (removals < minRemovals) {
            minRemovals = removals
        }
    }

    minRemovals
}
